#include <bits/stdc++.h>
using namespace std;

const int N=3e5+5;

int n,a[N],dep[N],f[N][21];
long long c[N];
vector<int> g[N];

void dfs(int x){
	dep[x]=dep[f[x][0]]+1;
	int len=g[x].size();
	for(int i=0;i<len;i++)
		if(g[x][i]!=f[x][0]){
			int v=g[x][i];
			f[v][0]=x;
			for(int j=1;f[f[v][j-1]][j-1];j++)
				f[v][j]=f[f[v][j-1]][j-1];
			dfs(v);
		}
}

void Sum(int x){
	int len=g[x].size();
	for(int i=0;i<len;i++)
		if(g[x][i]!=f[x][0])
			Sum(g[x][i]),c[x]+=c[g[x][i]]; 
}

int LCA(int x,int y){
	if(dep[x]<dep[y])
		swap(x,y);
	for(int i=20;i>=0;i--)
		if(dep[f[x][i]]>=dep[y])
			x=f[x][i];
	if(x==y)
		return x;
	for(int i=20;i>=0;i--)
		if(f[x][i]!=f[y][i])
			x=f[x][i],y=f[y][i];
	return f[x][0];
}

int main(){
	scanf("%d",&n);
	for(int i=1;i<=n;i++)
		scanf("%d",&a[i]);
	for(int i=1,u,v;i<n;i++){
		scanf("%d%d",&u,&v);
		g[u].push_back(v);
		g[v].push_back(u);
	}
	dfs(1);
	for(int i=2;i<=n;i++){
		int fa=LCA(a[i-1],a[i]);
		c[fa]--,c[a[i-1]]++;
		c[f[fa][0]]--,c[f[a[i]][0]]++;
	}
	Sum(1);
	for(int i=1;i<=n;i++)
		printf("%lld\n",c[i]);
	return 0;
}
